INSERT INTO public.notification_templates (slug, name, notification_type, subject_en, subject_bn, body_en, body_bn, variables) VALUES
('order_created', 'Order Created', 'email', 'Your Order #{{order_number}} has been placed', 'আপনার অর্ডার #{{order_number}} গৃহীত হয়েছে', 'Thank you for your order. Your order number is {{order_number}}. Total amount: {{total}} BDT.', 'আপনার অর্ডারের জন্য ধন্যবাদ। আপনার অর্ডার নম্বর {{order_number}}। মোট পরিমাণ: {{total}} টাকা।', '["order_number", "total", "customer_name"]'),
('invoice_generated', 'Invoice Generated', 'email', 'Invoice #{{invoice_number}} Generated', 'ইনভয়েস #{{invoice_number}} তৈরি হয়েছে', 'Your invoice #{{invoice_number}} for {{total}} BDT is ready. Due date: {{due_date}}.', 'আপনার ইনভয়েস #{{invoice_number}} {{total}} টাকার জন্য প্রস্তুত। শেষ তারিখ: {{due_date}}।', '["invoice_number", "total", "due_date"]'),
('payment_success', 'Payment Approved', 'email', 'Payment Approved - Order #{{order_number}}', 'পেমেন্ট অনুমোদিত - অর্ডার #{{order_number}}', 'Your payment for order #{{order_number}} has been verified and approved. Amount: {{amount}} BDT.', 'অর্ডার #{{order_number}} এর জন্য আপনার পেমেন্ট যাচাই এবং অনুমোদিত হয়েছে। পরিমাণ: {{amount}} টাকা।', '["order_number", "amount", "transaction_id"]'),
('service_activated', 'Service Activated', 'email', 'Your Service is Now Active', 'আপনার সেবা এখন সক্রিয়', 'Great news! Your {{service_name}} service has been activated.', 'দারুণ খবর! আপনার {{service_name}} সেবা সক্রিয় করা হয়েছে।', '["service_name", "activation_date"]'),
('renewal_reminder', 'Renewal Reminder', 'email', 'Renewal Reminder - {{service_name}}', 'নবায়ন স্মারক - {{service_name}}', 'Your {{service_name}} will expire on {{expiry_date}}. Please renew to avoid service interruption.', 'আপনার {{service_name}} {{expiry_date}} তারিখে মেয়াদ শেষ হবে। সেবা বাধা এড়াতে অনুগ্রহ করে নবায়ন করুন।', '["service_name", "expiry_date", "renewal_amount"]'),
('suspension_notice', 'Suspension Notice', 'email', 'Service Suspension Notice', 'সেবা স্থগিত বিজ্ঞপ্তি', 'Your {{service_name}} has been suspended due to {{reason}}. Please contact support.', 'আপনার {{service_name}} {{reason}} কারণে স্থগিত করা হয়েছে। অনুগ্রহ করে সহায়তায় যোগাযোগ করুন।', '["service_name", "reason"]')
